class Solution {
    public long minimumCost(String s) {
        int n = s.length();
        long res = 0;
        int cnt = 0;
        for (int i = 1; i < n; i++) {
            if (s.charAt(i) != s.charAt(i - 1)) {
                cnt++;
            }
        }
        return Math.min(cnt, n - cnt);
    }
}
